package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"
)

const (
	MaxUploadSize = 10 << 20
	UploadPath    = "./public/uploads"
)

var allowedExtensions = map[string]bool{
	".jpg":  true,
	".jpeg": true,
	".png":  true,
	".gif":  true,
	".bmp":  true,
	".webp": true,
	".svg":  true,
	".pdf":  true,
	".doc":  true,
	".docx": true,
	".xls":  true,
	".xlsx": true,
	".ppt":  true,
	".pptx": true,
	".txt":  true,
	".csv":  true,
	".zip":  true,
	".rar":  true,
	".7z":   true,
	".tar":  true,
	".gz":   true,
}

func init() {
	if err := os.MkdirAll(UploadPath, os.ModePerm); err != nil {
		panic(fmt.Sprintf("Failed to create upload directory: %v", err))
	}
}

func FileUploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	r.Body = http.MaxBytesReader(w, r.Body, MaxUploadSize)

	if err := r.ParseMultipartForm(MaxUploadSize); err != nil {
		http.Error(w, "File too large or invalid form data", http.StatusBadRequest)
		return
	}

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Failed to retrieve file from form", http.StatusBadRequest)
		return
	}
	defer file.Close()

	ext := strings.ToLower(filepath.Ext(header.Filename))
	if !allowedExtensions[ext] {
		http.Error(w, "File type not allowed", http.StatusBadRequest)
		return
	}

	timestamp := time.Now().Unix()
	baseFilename := strings.TrimSuffix(header.Filename, ext)
	baseFilename = sanitizeFilename(baseFilename)
	filename := fmt.Sprintf("%d_%s%s", timestamp, baseFilename, ext)
	
	filePath := filepath.Join(UploadPath, filename)

	dst, err := os.Create(filePath)
	if err != nil {
		http.Error(w, "Failed to create file on server", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, file); err != nil {
		http.Error(w, "Failed to save file", http.StatusInternalServerError)
		return
	}

	relativePath := filepath.Join("/uploads", filename)
	
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, `{"success": true, "path": "%s", "filename": "%s"}`, relativePath, filename)
}

func sanitizeFilename(filename string) string {
	replacer := strings.NewReplacer(
		"/", "_",
		"\\", "_",
		"..", "_",
		" ", "_",
	)
	return replacer.Replace(filename)
}

func main() {
	http.HandleFunc("/upload", FileUploadHandler)
	
	fs := http.FileServer(http.Dir("./public"))
	http.Handle("/uploads/", http.StripPrefix("/uploads/", http.FileServer(http.Dir(UploadPath))))
	
	fmt.Println("Server starting on :8080")
	fmt.Printf("Upload directory: %s\n", UploadPath)
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}